use anyhow::Result;
use ratatui::crossterm::event::{self, Event, KeyEventKind};
use ratatui::crossterm::terminal::{
    disable_raw_mode, enable_raw_mode, EnterAlternateScreen, LeaveAlternateScreen,
};
use ratatui::crossterm::ExecutableCommand;
use ratatui::{backend::CrosstermBackend, Terminal};
use std::io::{stdout, Write};

#[tokio::main]
async fn main() -> Result<()> {
    let mut app = app::App::new()?;

    enable_raw_mode()?;
    stdout().execute(EnterAlternateScreen)?;
    stdout().execute(ratatui::crossterm::event::EnableBracketedPaste)?;
    let mut terminal = Terminal::new(CrosstermBackend::new(stdout()))?;

    let res = run(&mut terminal, &mut app).await;

    disable_raw_mode()?;
    stdout().execute(LeaveAlternateScreen)?;
    stdout().execute(ratatui::crossterm::event::DisableBracketedPaste)?;
    terminal.show_cursor()?;
    stdout().flush()?;

    res
}

async fn run(
    terminal: &mut Terminal<CrosstermBackend<std::io::Stdout>>,
    app: &mut app::App,
) -> Result<()> {
    loop {
        terminal.draw(|f| ui::render::draw(f, app))?;

        let event = event::read()?;
        match event {
            Event::Key(key) if key.kind == KeyEventKind::Press => {
                if !app.handle_event(key.code) {
                    return Ok(());
                }
                if key.code == ratatui::crossterm::event::KeyCode::Char('r') && !app.show_config {
                    app.sync();
                }
            }
            Event::Paste(text) => {
                app.handle_paste(&text);
            }
            _ => {}
        }
    }
}

