impl App {
    pub fn new() -> Result<Self> {
        let (log_tx, log_rx) = mpsc::channel();
        match config::load_env()? {
            Some(cfg) => {
                let db = Arc::new(Database::open("iptv_cache.db")?);
                log_tx.send(format!("opened DB; Xtream URL: {}", cfg.url)).ok();
                let mut s = Self {
                    config: Some(cfg),
                    db: Some(db),
                    focus: Focus::Categories,
                    categories: Vec::new(),
                    movies: Vec::new(),
                    category_offset: 0,
                    movie_offset: 0,
                    selected_category: None,
                    show_config: false,
                    config_fields: ConfigFields::default(),
                    status: String::new(),
                    logs: Vec::new(),
                    log_rx,
                    log_tx: log_tx.clone(),
                    syncing: false,
                };
                s.load_categories();
                let n_cats = s.categories.len();
                if n_cats > 0 {
                    let n_movies = 0;
                    s.status = format!("{n_cats} categories, {n_movies} movies cached");
                    s.log_tx.send(format!("loaded {n_cats} categories from cache")).ok();
                } else {
                    s.status = "No cache — press r to sync".into();
                    s.log_tx.send("DB empty, waiting for sync".into()).ok();
                }
                Ok(s)
            }
            None => {
                log_tx.send("no .env found, showing config screen".into()).ok();
                Ok(Self {
                    config: None,
                    db: None,
                    focus: Focus::Categories,
                    categories: Vec::new(),
                    movies: Vec::new(),
                    category_offset: 0,
                    movie_offset: 0,
                    selected_category: None,
                    show_config: true,
                    config_fields: ConfigFields::default(),
                    status: "Configure your Xtream connection.".into(),
                    logs: Vec::new(),
                    log_rx,
                    log_tx,
                    syncing: false,
                })
            }
        }
    }

    pub fn drain_logs(&mut self) -> bool {
        let mut done = false;
        while let Ok(msg) = self.log_rx.try_recv() {
            if msg == "SYNC_DONE" {
                done = true;
                self.syncing = false;
                continue;
            }
            self.logs.push(msg);
            if self.logs.len() > MAX_LOG_LEN {
                self.logs.remove(0);
            }
        }
        done
    }

    pub fn log_tx(&self) -> mpsc::Sender<String> {
        self.log_tx.clone()
    }

